  const { startPeriod, endPeriod } = getYearsPeriod(
    monthDate,
    yearItemNumber,
  );
  return (
    <div className="react-datepicker__header react-datepicker-year-header">
      {showYearPicker ? `${startPeriod} - ${endPeriod}` : getYear(monthDate)}
    </div>
  );
